html:
{# Work Order Variation — variation order print format.
   Mirrors the WO Contract print's typography and signature layout so the
   variation looks like part of the same document family. Sections:
     1. Header (title + variation number + WO ref + meta)
     2. Reason for change (the justification being approved)
     3. The variation's own lines (signed qty + signed amounts)
     4. Contextual before/after via shared scope-map helper
     5. Signature block #}

<style>
  .wv-print, .wv-print * { box-sizing: border-box; }
  .wv-print {
    font-family: "Helvetica Neue", "Segoe UI", "Inter", Arial, sans-serif;
    color: #111;
    font-size: 9.5pt;
    line-height: 1.5;
    font-variant-numeric: tabular-nums;
    -webkit-font-feature-settings: "tnum";
    font-feature-settings: "tnum";
  }
  .wv-print p { margin: 0 0 6px; }

  .wv-print .display-title {
    font-family: "Georgia", "Times New Roman", "Cambria", serif;
    font-size: 24pt; font-weight: 700; letter-spacing: 4pt;
    text-align: center; color: #1a2942; margin: 0; line-height: 1.1;
  }
  .wv-print .display-sub {
    font-size: 9pt; letter-spacing: 3pt; text-transform: uppercase;
    text-align: center; color: #666; margin: 4px 0 0;
  }
  .wv-print .section-label {
    font-size: 8.5pt; letter-spacing: 2.5pt; text-transform: uppercase;
    color: #1a2942; font-weight: 600;
    margin: 22px 0 8px; padding-bottom: 4px;
    border-bottom: 1px solid #1a2942;
  }
  .wv-print .muted { color: #777; font-size: 8.5pt; }
  .wv-print .negative { color: #a91414; }

  /* Cover block */
  .wv-print .cover-block {
    border-top: 3px solid #1a2942; border-bottom: 1px solid #1a2942;
    padding: 18px 0 16px; margin-bottom: 22px;
  }
  .wv-print .cover-meta {
    margin-top: 14px; display: table; width: 100%;
    border-collapse: collapse;
  }
  .wv-print .cover-meta > div {
    display: table-cell; padding: 0 6px; vertical-align: top;
    width: 33.33%; text-align: center;
  }
  .wv-print .meta-label {
    font-size: 7.5pt; letter-spacing: 1.5pt; text-transform: uppercase;
    color: #888; margin-bottom: 2px;
  }
  .wv-print .meta-value {
    font-size: 11pt; font-weight: 600; color: #1a2942;
    letter-spacing: 0.3pt;
  }
  .wv-print .status-pill {
    display: inline-block; padding: 1px 8px;
    font-size: 7.5pt; letter-spacing: 1.5pt; text-transform: uppercase;
    font-weight: 600; border: 1px solid #1a2942; color: #1a2942;
    border-radius: 2px;
  }
  .wv-print .status-pill.cancelled { color: #a91414; border-color: #a91414; }
  .wv-print .status-pill.draft     { color: #b75c00; border-color: #b75c00; }

  /* Parties block — slimmer than WO contract since the WO is referenced */
  .wv-print .parties { width: 100%; border-collapse: collapse; margin: 0 0 8px; }
  .wv-print .parties td { width: 50%; padding: 12px 16px 12px 0; vertical-align: top; }
  .wv-print .parties td + td { padding-left: 16px; border-left: 1px solid #ddd; }
  .wv-print .party-role {
    font-size: 7.5pt; letter-spacing: 2pt; text-transform: uppercase;
    color: #888; margin-bottom: 3px;
  }
  .wv-print .party-name { font-size: 11pt; font-weight: 700; color: #111; line-height: 1.3; }

  /* Reason callout */
  .wv-print .reason-block {
    background: #faf8f3; border-left: 3px solid #c9a25a;
    padding: 10px 14px; margin: 10px 0 16px;
    font-size: 10pt; color: #4d3a14; line-height: 1.5;
  }
  .wv-print .reason-block .reason-label {
    font-size: 7.5pt; letter-spacing: 2pt; text-transform: uppercase;
    color: #8b6c2c; font-weight: 600; margin-bottom: 4px;
  }

  /* Tables */
  .wv-print .lines-table { width: 100%; border-collapse: collapse; margin: 0 0 12px; font-size: 9pt; }
  .wv-print .lines-table th, .wv-print .lines-table td {
    padding: 6px 6px; border-bottom: 1px solid #e6e6e6; vertical-align: top;
  }
  .wv-print .lines-table thead th {
    background: #1a2942; color: #fff; text-align: left;
    font-size: 7.5pt; letter-spacing: 0.8pt; text-transform: uppercase;
    font-weight: 600; padding: 6px 6px;
  }
  .wv-print .lines-table th.amt, .wv-print .lines-table td.amt {
    text-align: right; white-space: nowrap;
  }
  .wv-print .lines-table tfoot td {
    background: #1a2942; color: #fff; font-weight: 700;
    font-size: 10pt; padding: 8px 6px; letter-spacing: 0.4pt;
    border-bottom: none;
  }
  .wv-print .type-tag {
    display: inline-block; padding: 1px 6px; font-size: 7.5pt;
    letter-spacing: 0.5pt; font-weight: 600; border-radius: 2px;
    border: 1px solid #ccc; color: #555; background: #fafafa;
  }
  .wv-print .type-tag.add { color: #155724; border-color: #155724; background: #e9f5ee; }
  .wv-print .type-tag.new { color: #155a98; border-color: #155a98; background: #eaf2fb; }
  .wv-print .type-tag.red { color: #a91414; border-color: #a91414; background: #fdecec; }

  /* Before/after table */
  .wv-print .ba-table { width: 100%; border-collapse: collapse; margin: 4px 0 8px; font-size: 9pt; }
  .wv-print .ba-table th, .wv-print .ba-table td {
    padding: 6px 8px; border-bottom: 1px solid #e6e6e6; vertical-align: top;
  }
  .wv-print .ba-table thead th {
    background: #f5f5f3; text-align: left;
    font-size: 7.5pt; letter-spacing: 1.2pt; text-transform: uppercase;
    color: #555; font-weight: 600; border-bottom: 1px solid #999;
  }
  .wv-print .ba-table th.amt, .wv-print .ba-table td.amt {
    text-align: right; white-space: nowrap;
  }
  .wv-print .ba-table .delta-pos { color: #155724; font-weight: 700; }
  .wv-print .ba-table .delta-neg { color: #a91414; font-weight: 700; }

  /* Amount-in-words & footer */
  .wv-print .amount-in-words {
    background: #faf8f3; border-left: 3px solid #c9a25a;
    padding: 10px 14px; margin: 10px 0 6px;
    font-style: italic; color: #4d3a14; font-size: 9.5pt;
  }
  .wv-print .doc-footnote {
    margin-top: 22px; padding-top: 8px; border-top: 1px solid #e8e8e8;
    font-size: 8pt; color: #888; text-align: center; line-height: 1.4;
  }

  /* Signature block — mirror WO contract */
  .wv-print .signature-block { margin-top: 28px; page-break-inside: avoid; }
  .wv-print .sig-grid {
    width: 100%; border-collapse: separate;
    border-spacing: 24px 0; margin-top: 6px;
  }
  .wv-print .sig-grid td { width: 50%; padding: 0; vertical-align: top; }
  .wv-print .sig-role {
    font-size: 7.5pt; letter-spacing: 2pt; text-transform: uppercase;
    color: #888; margin-bottom: 4px;
  }
  .wv-print .sig-name {
    font-size: 10pt; font-weight: 700; color: #111;
    line-height: 1.35; min-height: 42px; margin-bottom: 30px;
    display: flex; align-items: flex-start;
  }
  .wv-print .sig-line { border-top: 1px solid #333; margin-bottom: 4px; }
  .wv-print .sig-caption {
    font-size: 8.5pt; color: #555; font-weight: 600; margin-bottom: 6px;
  }
  .wv-print .sig-detail {
    font-size: 8.5pt; color: #777; line-height: 1.7;
  }
  .wv-print .sig-detail span {
    display: inline-block; min-width: 60pt;
    border-bottom: 1px dotted #999; padding: 0 6px;
  }
</style>

{# Helpers — match the WO contract print's macros so currency etc. format identically #}
{%- set company_currency = frappe.db.get_value("Company", doc.company, "default_currency") or "INR" -%}
{%- macro money(amt) -%}{% if amt is none %}—{% else %}{{ frappe.utils.fmt_money(amt or 0, currency=company_currency) }}{% endif %}{%- endmacro -%}
{%- macro show_date(d) -%}{%- if d -%}{{ frappe.utils.formatdate(d, "dd MMM yyyy") }}{%- else -%}—{%- endif -%}{%- endmacro -%}
{%- macro qty(v) -%}{% if v is none %}—{% else %}{{ "{:,.3f}".format(v|float) }}{% endif %}{%- endmacro -%}
{%- macro signed_qty(v) -%}{% if v is none %}—{% elif (v|float) < 0 %}<span class="negative">{{ "{:,.3f}".format(v|float) }}</span>{% else %}{{ "{:,.3f}".format(v|float) }}{% endif %}{%- endmacro -%}
{%- macro signed_money(v) -%}{% if v is none %}—{% elif (v|float) < 0 %}<span class="negative">{{ frappe.utils.fmt_money(v|float, currency=company_currency) }}</span>{% else %}{{ frappe.utils.fmt_money(v|float, currency=company_currency) }}{% endif %}{%- endmacro -%}

{# Look up the parent WO for context, plus the shared scope map and
   original BOQ qtys via the variation's own controller methods (the
   Jinja sandbox blocks frappe.get_attr, so we go through `doc.<method>`
   which is safe). Both methods use the SAME shared helper RA Bill
   allocation uses, so "resulting total sanctioned" in the before/after
   section can never disagree with what gets billed. #}
{%- set wo = frappe.get_doc("Work Order Contract", doc.work_order_contract) -%}
{%- set scope_by_key = doc.get_print_scope_summary() -%}
{%- set orig_qty_by_uid = doc.get_print_original_qtys() -%}

<div class="wv-print">

{# 1. HEADER #}
<div class="cover-block">
  <h1 class="display-title">VARIATION ORDER</h1>
  <p class="display-sub">Variation No. {{ "%d"|format(doc.variation_number or 0) }} &nbsp;·&nbsp; to Work Order {{ doc.work_order_contract }}</p>
  <div class="cover-meta">
    <div>
      <div class="meta-label">Variation No.</div>
      <div class="meta-value">{{ doc.name }}</div>
    </div>
    <div>
      <div class="meta-label">Variation Date</div>
      <div class="meta-value">{{ show_date(doc.variation_date) }}</div>
    </div>
    <div>
      <div class="meta-label">Status</div>
      <div class="meta-value">
        {%- if doc.docstatus == 0 -%}<span class="status-pill draft">Draft</span>
        {%- elif doc.docstatus == 1 -%}<span class="status-pill">Approved</span>
        {%- elif doc.docstatus == 2 -%}<span class="status-pill cancelled">Cancelled</span>
        {%- endif -%}
      </div>
    </div>
  </div>
</div>

<table class="parties">
  <tr>
    <td>
      <div class="party-role">Employer</div>
      <div class="party-name">{{ doc.company }}</div>
    </td>
    <td>
      <div class="party-role">Contractor</div>
      <div class="party-name">{{ wo.supplier_name or doc.supplier }}</div>
    </td>
  </tr>
</table>

<div class="muted" style="margin: 6px 0 0;">
  <strong>Parent Work Order:</strong> {{ doc.work_order_contract }}{% if wo.work_title %} — {{ wo.work_title }}{% endif %}
</div>

{# 2. REASON FOR CHANGE #}
<div class="section-label">Reason for Change</div>
<div class="reason-block">
  <div class="reason-label">Justification</div>
  {{ doc.reason_for_change or "—" }}
</div>

{# 3. THIS VARIATION'S OWN LINES #}
<div class="section-label">Variation Lines</div>
<table class="lines-table">
  <colgroup>
    <col style="width: 8%;">
    <col style="width: 10%;">
    <col>
    <col style="width: 7%;">
    <col style="width: 7%;">
    <col style="width: 9%;">
    <col style="width: 7%;">
    <col style="width: 12%;">
    <col style="width: 13%;">
  </colgroup>
  <thead>
    <tr>
      <th>Item</th>
      <th>Type</th>
      <th>Description</th>
      <th>UOM</th>
      <th class="amt">Var Qty</th>
      <th class="amt">Rate</th>
      <th class="amt">Tax %</th>
      <th class="amt">Amount</th>
      <th class="amt">Amount (incl.)</th>
    </tr>
  </thead>
  <tbody>
    {% for r in (doc.variation_items or []) %}
    {%- set tag_class = "add" if r.line_type == "Additional Qty" else ("new" if r.line_type == "New Item" else "red") -%}
    <tr>
      <td>{{ r.item_no or "" }}</td>
      <td><span class="type-tag {{ tag_class }}">{{ r.line_type }}</span></td>
      <td>{{ r.description or "" }}</td>
      <td>{{ r.uom or "" }}</td>
      <td class="amt">{{ signed_qty(r.qty) }}</td>
      <td class="amt">{{ money(r.rate) }}</td>
      <td class="amt">{{ "%.2f"|format(r.tax_pct|float if r.tax_pct is not none else 0) }}%</td>
      <td class="amt">{{ signed_money(r.amount) }}</td>
      <td class="amt">{{ signed_money(r.amount_with_tax) }}</td>
    </tr>
    {% endfor %}
  </tbody>
  <tfoot>
    <tr>
      <td colspan="7">VARIATION TOTAL</td>
      <td class="amt">{{ signed_money(doc.total_amount) }}</td>
      <td class="amt">{{ signed_money(doc.total_amount_with_tax) }}</td>
    </tr>
  </tfoot>
</table>

<div class="amount-in-words">
  Net variation value (incl. tax): {% if (doc.total_amount_with_tax or 0) < 0 %}<span class="negative">[Reduction]</span> {% endif %}{{ frappe.utils.money_in_words((doc.total_amount_with_tax or 0)|abs, company_currency) }}
</div>

{# 4. CONTEXTUAL BEFORE / AFTER (via shared helper)
   For each line that references an existing original BOQ row (Additional
   Qty / Reduced Qty), show the contract-frozen Original Qty, this
   variation's delta, and the CURRENT consolidated total sanctioned from
   the shared helper. Labelled clearly so the approver knows the "after"
   reflects all approved variations on this WO, not just this one. #}
{%- set ba_rows = [] -%}
{%- set seen_uids = {} -%}
{%- for r in (doc.variation_items or []) -%}
  {%- if r.line_type in ("Additional Qty", "Reduced Qty") and r.original_boq_row_uid -%}
    {%- if seen_uids.update({r.original_boq_row_uid: True}) -%}{%- endif -%}
    {%- set _ = ba_rows.append({
      "item_no": r.item_no,
      "description": r.description,
      "uom": r.uom,
      "original_qty": orig_qty_by_uid.get(r.original_boq_row_uid),
      "delta": r.qty,
      "current_total_qty": (scope_by_key.get(r.original_boq_row_uid) or {}).get("total_qty"),
    }) -%}
  {%- endif -%}
{%- endfor -%}

{%- set new_item_rows = [] -%}
{%- for r in (doc.variation_items or []) -%}
  {%- if r.line_type == "New Item" -%}
    {%- set _ = new_item_rows.append({
      "item_no": r.item_no,
      "description": r.description,
      "uom": r.uom,
      "delta": r.qty,
    }) -%}
  {%- endif -%}
{%- endfor -%}

{% if ba_rows or new_item_rows %}
<div class="section-label">Effect on Item Quantities</div>
<p class="muted" style="margin-top: -2px; font-size: 8.5pt; line-height: 1.5;">
  <strong>Resulting Total Sanctioned Qty</strong> is the item's current
  consolidated sanctioned quantity considering the original BOQ plus
  <strong>all approved variations</strong> on this Work Order — this is the
  same single-source-of-truth number used by the consolidated Variation
  Summary report and by RA Bill allocation, so what is approved here is
  what gets billed.
</p>
<table class="ba-table">
  <colgroup>
    <col style="width: 8%;"><col><col style="width: 8%;">
    <col style="width: 14%;"><col style="width: 16%;"><col style="width: 16%;">
  </colgroup>
  <thead>
    <tr>
      <th>Item</th>
      <th>Description</th>
      <th>UOM</th>
      <th class="amt">Original Qty</th>
      <th class="amt">This Variation Δ</th>
      <th class="amt">Resulting Total Sanctioned</th>
    </tr>
  </thead>
  <tbody>
    {% for ba in ba_rows %}
    <tr>
      <td>{{ ba.item_no or "" }}</td>
      <td>{{ ba.description or "" }}</td>
      <td>{{ ba.uom or "" }}</td>
      <td class="amt">{{ qty(ba.original_qty) }} <span class="muted">{{ ba.uom or "" }}</span></td>
      <td class="amt {% if (ba.delta or 0) < 0 %}delta-neg{% else %}delta-pos{% endif %}">{{ signed_qty(ba.delta) }} <span class="muted">{{ ba.uom or "" }}</span></td>
      <td class="amt">{{ qty(ba.current_total_qty) }} <span class="muted">{{ ba.uom or "" }}</span></td>
    </tr>
    {% endfor %}
    {% for nr in new_item_rows %}
    <tr>
      <td>{{ nr.item_no or "" }}</td>
      <td>{{ nr.description or "" }} <span class="muted">(new item)</span></td>
      <td>{{ nr.uom or "" }}</td>
      <td class="amt muted">—</td>
      <td class="amt delta-pos">{{ signed_qty(nr.delta) }} <span class="muted">{{ nr.uom or "" }}</span></td>
      <td class="amt">{{ qty(nr.delta) }} <span class="muted">{{ nr.uom or "" }}</span></td>
    </tr>
    {% endfor %}
  </tbody>
</table>
{% endif %}

{# 5. SIGNATURES — mirror WO contract layout #}
<div class="signature-block">
  <div class="section-label" style="margin-top: 0;">Approval</div>
  <p class="muted" style="margin-top: -4px;">This Variation Order forms an integral part of Work Order {{ doc.work_order_contract }}. By their signatures below, the parties accept the changes described above.</p>
  <table class="sig-grid">
    <tr>
      <td>
        <div class="sig-role">For the Employer</div>
        <div class="sig-name">{{ doc.company }}</div>
        <div class="sig-line"></div>
        <div class="sig-caption">Authorized Signatory</div>
        <div class="sig-detail">
          Name <span></span><br>
          Designation <span></span><br>
          Place <span></span> &nbsp; Date <span></span>
        </div>
      </td>
      <td>
        <div class="sig-role">For the Contractor</div>
        <div class="sig-name">{{ wo.supplier_name or doc.supplier }}</div>
        <div class="sig-line"></div>
        <div class="sig-caption">Authorized Signatory</div>
        <div class="sig-detail">
          Name <span></span><br>
          Designation <span></span><br>
          Place <span></span> &nbsp; Date <span></span>
        </div>
      </td>
    </tr>
  </table>
</div>

<div class="doc-footnote">
  This Variation Order is a computer-generated document. It is binding upon authorized signatures of both parties.<br>
  {{ doc.name }} &nbsp;·&nbsp; to Work Order {{ doc.work_order_contract }} &nbsp;·&nbsp; Generated from {{ doc.company }}'s contract management system.
</div>

</div>{# /.wv-print #}
